/**
 * Unit tests for pre-commit-simulation hook
 * Tests pre-commit/husky detection and --no-verify warnings for git commit
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../../fixtures/mock-common.js';

vi.mock('../../../lib/common.js', () => mockCommonBasic());

vi.mock('node:fs', () => ({
  existsSync: vi.fn(() => false),
}));

vi.mock('node:path', () => {
  const named = {
    join: vi.fn((...args: string[]) => args.join('/')),
    basename: vi.fn((p: string) => p.split('/').pop() || ''),
    dirname: vi.fn((p: string) => p.split('/').slice(0, -1).join('/')),
    resolve: vi.fn((...a: string[]) => a.join('/')),
    sep: '/',
  };
  return { ...named, default: named };
});

import { preCommitSimulation } from '../../../pretool/bash/pre-commit-simulation.js';
import type { HookInput } from '../../../types.js';
import { existsSync } from 'node:fs';
import { createTestContext } from '../../fixtures/test-context.js';

function makeInput(command: string): HookInput {
  return {
    tool_name: 'Bash',
    session_id: 'test-session-123',
    project_dir: '/test/project',
    tool_input: { command },
  };
}

let ctx: ReturnType<typeof createTestContext>;

describe('pre-commit-simulation', () => {
  beforeEach(() => {
    ctx = createTestContext();
    vi.clearAllMocks();
    vi.mocked(existsSync).mockReturnValue(false);
  });

  // --- Silent cases ---

  it('returns silent success for non-commit commands', () => {
    const result = preCommitSimulation(makeInput('git push origin main'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
    expect(result.hookSpecificOutput).toBeUndefined();
  });

  it('returns silent success for npm test', () => {
    const result = preCommitSimulation(makeInput('npm test'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('returns silent success when no pre-commit config found', () => {
    // existsSync returns false by default — no config files
    const result = preCommitSimulation(makeInput('git commit -m "test"'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
    expect(result.hookSpecificOutput).toBeUndefined();
  });

  // --- Warning cases ---

  it('warns on --no-verify flag', () => {
    const result = preCommitSimulation(makeInput('git commit --no-verify -m "skip hooks"'), ctx);

    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.additionalContext).toContain('WARNING');
    expect(result.hookSpecificOutput?.additionalContext).toContain('--no-verify');
    expect(result.hookSpecificOutput?.additionalContext).toContain('skip pre-commit hooks');
  });

  it('logs --no-verify detection', () => {
    preCommitSimulation(makeInput('git commit --no-verify -m "quick"'), ctx);

    expect(ctx.logPermission).toHaveBeenCalledWith('allow', 'Skip pre-commit detected', expect.any(Object));
    expect(ctx.log).toHaveBeenCalledWith('pre-commit-simulation', '--no-verify used');
  });

  // --- Config detection cases ---

  it('returns pre-commit context when .pre-commit-config.yaml exists', () => {
    vi.mocked(existsSync).mockImplementation((p: unknown) => {
      return String(p).includes('.pre-commit-config.yaml');
    });

    const result = preCommitSimulation(makeInput('git commit -m "add feature"'), ctx);

    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.additionalContext).toContain('.pre-commit-config.yaml');
    expect(result.hookSpecificOutput?.additionalContext).toContain('pre-commit run --all-files');
  });

  it('returns husky context when .husky/ exists', () => {
    vi.mocked(existsSync).mockImplementation((p: unknown) => {
      return String(p).includes('.husky');
    });

    const result = preCommitSimulation(makeInput('git commit -m "add feature"'), ctx);

    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.additionalContext).toContain('Husky');
    expect(result.hookSpecificOutput?.additionalContext).toContain('.husky/');
  });

  it('prefers pre-commit config over husky when both exist', () => {
    vi.mocked(existsSync).mockReturnValue(true);

    const result = preCommitSimulation(makeInput('git commit -m "both configs"'), ctx);

    // pre-commit-config is checked first
    expect(result.hookSpecificOutput?.additionalContext).toContain('.pre-commit-config');
    expect(result.hookSpecificOutput?.additionalContext).not.toContain('Husky');
  });

  it('logs permission on pre-commit config detection', () => {
    vi.mocked(existsSync).mockImplementation((p: unknown) => {
      return String(p).includes('.pre-commit-config.yaml');
    });

    preCommitSimulation(makeInput('git commit -m "test"'), ctx);

    expect(ctx.logPermission).toHaveBeenCalledWith('allow', 'pre-commit config found', expect.any(Object));
  });

  it('logs permission on husky detection', () => {
    vi.mocked(existsSync).mockImplementation((p: unknown) => {
      return String(p).includes('.husky');
    });

    preCommitSimulation(makeInput('git commit -m "test"'), ctx);

    expect(ctx.logPermission).toHaveBeenCalledWith('allow', 'husky config found', expect.any(Object));
  });
});
